SELECT * FROM (
    SELECT
        h.ORG_ID AS orgId,
        h.TRX_TYPE AS trxType,
        h.IO_TYPE AS ioType,
        h.OPER_MODE_TYPE AS operModeType,
        h.HANDLER AS handler,
        h.HANDLER_DESC AS handlerDesc,
        h.STOP_YN AS stopYn,
        ROW_NUMBER() OVER (ORDER BY ${orderColumn} ${orderDir}) AS RN



            AND h.ORG_ID = #{orgId}


            AND h.TRX_TYPE = #{trxType}


            AND h.IO_TYPE = #{ioType}


)
WHERE RN BETWEEN #{offset} + 1 AND #{offset} + #{limit}
ORDER BY RN

